import './home.css'
import { useAuth } from "../../Context/useAuth";
import { useNavigate, Outlet, useLocation } from "react-router-dom";
import Sidebar from "../SideBar/Sidebar";
import { AnimatePresence, motion } from "framer-motion";

import { useQueryClient } from '@tanstack/react-query';
import Editor from "./Editor/Editor";
import { useLexicalComposerContext } from "@lexical/react/LexicalComposerContext";
import MobileNavlink from "../mobileNavLink/MobileNavLink";
import WriteJournalButton from "../WriteJournalButton/WriteJournalButton";
import MobileSidebarLink from "../MobileSidebarLink/MobileSidebarLink";
import OnboardingWizard from "../Onboarding/OnboardingWizard";
import Loader from "../loadingComponent/BgLoader";
import SidebarOpinions from "../SidebarOpinions/SidebarOpinions";
import OpinionEditor from "../SidebarOpinions/OpinionsEditor";

import { useMediaQuery } from 'react-responsive';

const DEFAULT_EDITOR_LAUNCH_CONFIG = {
    initialTitle: '',
    promptId: null,
    promptText: null,
    draftId: null,
    draftContent: null,
};

const HomePage = () => {
    const {session, signOut, user, loading, isLoading, notifCount, openAuthModal} = useAuth();
    const isGuest = !session && !loading;

    const userId = user?.userData?.[0]?.id || null;

    const isMobile = useMediaQuery({query: '(max-width: 480px)'});

    const navigate = useNavigate();
    const location = useLocation();

    const queryClient = useQueryClient();
    const [editor] = useLexicalComposerContext();

    const [showMobileSideBar, setShowMobileSideBar] = useState(false);

    const isOpinionsPage = location.pathname === '/home/opinions';
    const isOpinionsViewer = location.pathname === '/home/opinionsViewer';

    const navigatePath = useCallback((path) => {
        if(window.location.pathname === path){
           return window.location.reload()
        }
        return navigate(path);
    }, [navigate])

    const [showOnboarding, setShowOnboarding] = useState(false);
    const [onboardingUserExists, setOnboardingUserExists] = useState(false);
    const [showEditor, setShowEditor] = useState(false);
    const [editorLaunchConfig, setEditorLaunchConfig] = useState(DEFAULT_EDITOR_LAUNCH_CONFIG);

    const [showOpinionEditor, setShowOpinionEditor] = useState(false);

    const handleOpenTextEditor = useCallback((config = {}) => {
        editor.setEditable(true)
        setEditorLaunchConfig({
            ...DEFAULT_EDITOR_LAUNCH_CONFIG,
            ...config
        });
        setShowEditor(true)
    }, [editor])
    const handleCloseEditor = useCallback(() => {
        setShowEditor(false)
        setEditorLaunchConfig(DEFAULT_EDITOR_LAUNCH_CONFIG);
    }, [])

    const links = useMemo(() => {
        const activeColor = "#5f92ffff";
        const inactiveColor = "#b6b6b6ff";
        const pathname = location.pathname;

        const homeLink = {
            path: '/home',
            label: 'Home',
            action: ()=> navigatePath('/home'),
            icon:
            <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="#000000ff">
                <g id="style=fill">
                    <g id="home-line" clipPath="url(#clip0_1_110)">
                        <path id="Subtract" fillRule="evenodd" clipRule="evenodd" d="M14.3594 2.12613C13.0087 0.944612 10.9923 0.94461 9.64162 2.12612L3.2802 7.69086C2.29508 8.55261 1.72998 9.79772 1.72998 11.1066L1.72998 19.1672C1.72998 21.1459 3.33403 22.75 5.31273 22.75L18.6883 22.75C20.667 22.75 22.271 21.1459 22.271 19.1672L22.271 11.1066C22.271 9.79772 21.706 8.55261 20.7208 7.69086L14.3594 2.12613ZM10 16.1136C9.58579 16.1136 9.25 16.4494 9.25 16.8636C9.25 17.2779 9.58579 17.6136 10 17.6136L14 17.6136C14.4142 17.6136 14.75 17.2779 14.75 16.8636C14.75 16.4494 14.4142 16.1136 14 16.1136L10 16.1136Z" fill={pathname === '/home' ? activeColor : inactiveColor}/>
                    </g>
                </g>
            </svg>
        };

        const exploreLink = {
            path: '/home/explore',
            label: 'Explore',
            action: () => navigatePath('/home/explore'),
            icon:
            <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="#000000">
                <path fillRule="evenodd" d="M12,2 C17.5228475,2 22,6.4771525 22,12 C22,17.5228475 17.5228475,22 12,22 C6.4771525,22 2,17.5228475 2,12 C2,6.4771525 6.4771525,2 12,2 Z M17.9842695,7.39078625 C18.1985588,6.64477525 17.4973604,5.9435768 16.7513494,6.1578661 L16.6494246,6.19284365 L9.57835679,9.02127078 L9.47282273,9.07079854 C9.30957453,9.15937167 9.17428758,9.29167162 9.08209683,9.45256344 L9.02127078,9.57835679 L6.19284365,16.6494246 L6.1578661,16.7513494 C5.9435768,17.4973604 6.64477525,18.1985588 7.39078625,17.9842695 L7.49271102,17.949292 L14.5637788,15.1208648 L14.6693129,15.0713371 C14.8325611,14.982764 14.967848,14.850464 15.0600388,14.6895722 L15.1208648,14.5637788 L17.949292,7.49271102 L17.9842695,7.39078625 Z M12,10 C13.1045695,10 14,10.8954305 14,12 C14,13.1045695 13.1045695,14 12,14 C10.8954305,14 10,13.1045695 10,12 C10,10.8954305 10.8954305,10 12,10 Z" fill={pathname === '/home/explore' ? activeColor : inactiveColor} />
            </svg>
        };

        if (isGuest) {
            return [homeLink, exploreLink,
                { label: 'Log in', action: () => navigate('/login'), className: 'write-journal-bttn' },
                { label: 'Sign up', action: () => navigate('/signUp'), className: 'sidebar-links' },
            ];
        }

        return [homeLink, exploreLink,
            {
                path: '/profile',
                label: 'Profile', action: ()=> navigatePath('/profile'),
                icon:
                <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="#000000ff">
                    <g id="style=fill">
                        <g id="profile">
                            <path id="vector (Stroke)" fillRule="evenodd" clipRule="evenodd" d="M6.75 6.5C6.75 3.6005 9.1005 1.25 12 1.25C14.8995 1.25 17.25 3.6005 17.25 6.5C17.25 9.3995 14.8995 11.75 12 11.75C9.1005 11.75 6.75 9.3995 6.75 6.5Z" fill={pathname === '/profile' ? activeColor : inactiveColor}/>
                            <path id="rec (Stroke)" fillRule="evenodd" clipRule="evenodd" d="M4.25 18.5714C4.25 15.6325 6.63249 13.25 9.57143 13.25H14.4286C17.3675 13.25 19.75 15.6325 19.75 18.5714C19.75 20.8792 17.8792 22.75 15.5714 22.75H8.42857C6.12081 22.75 4.25 20.8792 4.25 18.5714Z" fill={pathname === '/profile' ? activeColor : inactiveColor}/>
                        </g>
                    </g>
                </svg>
            },
            {
                path: '/home/notifications',
                label: 'Notifications',
                notifCount: notifCount > 0 ? notifCount : '',
                action: () => navigate('/home/notifications'),
                icon:
                <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="#000000ff">
                    <g id="style=fill">
                        <g id="notification-bell">
                            <path id="vector (Stroke)" fillRule="evenodd" clipRule="evenodd" d="M14.802 19.8317C15.4184 19.7699 15.8349 20.4242 15.5437 20.9539C15.3385 21.3271 15.0493 21.6529 14.7029 21.9197C14.3496 22.1918 13.9397 22.4006 13.5 22.5408C13.0601 22.6812 12.593 22.7522 12.1242 22.7522C11.6554 22.7522 11.1883 22.6812 10.7484 22.5408C10.3087 22.4006 9.89883 22.1918 9.54556 21.9197C9.1991 21.6529 8.90988 21.3271 8.70472 20.9539C8.41354 20.4242 8.83002 19.7699 9.44644 19.8317C9.63869 19.851 11.1433 19.9981 12.1242 19.9981C13.1051 19.9981 14.6097 19.851 14.802 19.8317Z" fill={pathname === '/home/notifications' ? activeColor : inactiveColor}/>
                            <path id="vector (Stroke)_2" fillRule="evenodd" clipRule="evenodd" d="M8.52901 2.08755C10.7932 1.00445 13.4465 0.967602 15.7423 1.98737L15.9475 2.07851C18.3532 3.14707 19.8934 5.4622 19.8934 8.0096L19.8934 9.27297C19.8934 10.2885 20.1236 11.2918 20.5681 12.213L20.8335 12.7632C22.0525 15.29 20.465 18.2435 17.6156 18.7498L17.455 18.7783C13.93 19.4046 10.3154 19.4046 6.79044 18.7783C3.90274 18.2653 2.37502 15.1943 3.77239 12.7115L3.99943 12.3082C4.55987 11.3124 4.85335 10.1981 4.85335 9.06596L4.85335 7.79233C4.85335 5.3744 6.27704 3.16478 8.52901 2.08755Z" fill={pathname === '/home/notifications' ? activeColor : inactiveColor}/>
                        </g>
                    </g>
                </svg>
            },
            {
                path: '/home/bookmark',
                label: 'Bookmarks',
                action: ()=> navigatePath('/home/bookmark'),
                icon:
                <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="none">
                    <g id="style=fill">
                        <g id="bookmark">
                        <path id="Subtract" fillRule="evenodd" clipRule="evenodd" d="M8 1.25C5.37665 1.25 3.25 3.37665 3.25 6V20.4648C3.25 21.7269 4.27311 22.75 5.53518 22.75C5.98634 22.75 6.42739 22.6165 6.80278 22.3662L11.3066 19.3636C11.7265 19.0837 12.2735 19.0837 12.6934 19.3636L17.1972 22.3662C17.5726 22.6165 18.0137 22.75 18.4648 22.75C19.7269 22.75 20.75 21.7269 20.75 20.4648V6C20.75 3.37665 18.6234 1.25 16 1.25H8ZM9 6.75C8.58579 6.75 8.25 7.08579 8.25 7.5C8.25 7.91421 8.58579 8.25 9 8.25H15C15.4142 8.25 15.75 7.91421 15.75 7.5C15.75 7.08579 15.4142 6.75 15 6.75H9Z" fill={pathname === '/home/bookmark' ? activeColor : inactiveColor}/>
                        </g>
                    </g>
                </svg>
            },
            {
                path: '/home/drafts',
                label: 'Drafts',
                action: () => navigatePath('/home/drafts'),
                icon:
                <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill={pathname === '/home/drafts' ? activeColor : inactiveColor}>
                    <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8l-6-6z"/>
                    <polyline points="14 2 14 8 20 8" fill="none" stroke={pathname === '/home/drafts' ? activeColor : inactiveColor} strokeWidth="1"/>
                    <line x1="16" y1="13" x2="8" y2="13" stroke={pathname === '/home/drafts' ? '#fff' : inactiveColor} strokeWidth="2" strokeLinecap="round"/>
                    <line x1="16" y1="17" x2="8" y2="17" stroke={pathname === '/home/drafts' ? '#fff' : inactiveColor} strokeWidth="2" strokeLinecap="round"/>
                </svg>
            },
            {
                path: '/home/analytics',
                label: 'Analytics',
                action: () => navigatePath('/home/analytics'),
                icon:
                <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill={pathname === '/home/analytics' ? activeColor : inactiveColor}>
                    <path d="M3 3v18h18" stroke={pathname === '/home/analytics' ? activeColor : inactiveColor} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" fill="none"/>
                    <path d="M7 17V13" stroke={pathname === '/home/analytics' ? activeColor : inactiveColor} strokeWidth="2" strokeLinecap="round"/>
                    <path d="M11 17V9" stroke={pathname === '/home/analytics' ? activeColor : inactiveColor} strokeWidth="2" strokeLinecap="round"/>
                    <path d="M15 17V5" stroke={pathname === '/home/analytics' ? activeColor : inactiveColor} strokeWidth="2" strokeLinecap="round"/>
                    <path d="M19 17V11" stroke={pathname === '/home/analytics' ? activeColor : inactiveColor} strokeWidth="2" strokeLinecap="round"/>
                </svg>
            },
            {
                path: '/home/settings',
                label: 'Settings',
                action: () => navigatePath('/home/settings'),
                icon:
                <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill={pathname === '/home/settings' ? "#5f92ff" : "#b6b6b6"}>
                    <path d="M12 15.5A3.5 3.5 0 1 0 12 8.5a3.5 3.5 0 0 0 0 7Z"/>
                    <path d="M19.43 12.98c.04-.32.07-.64.07-.98 0-.34-.03-.66-.07-.98l2.11-1.65a.5.5 0 0 0 .12-.64l-2-3.46a.5.5 0 0 0-.61-.22l-2.49 1a7.04 7.04 0 0 0-1.69-.98l-.38-2.65A.49.49 0 0 0 14 2h-4a.49.49 0 0 0-.49.42l-.38 2.65c-.61.25-1.17.59-1.69.98l-2.49-1a.5.5 0 0 0-.61.22l-2 3.46a.49.49 0 0 0 .12.64l2.11 1.65c-.04.32-.07.65-.07.98 0 .33.03.66.07.98l-2.11 1.65a.5.5 0 0 0-.12.64l2 3.46c.12.22.39.3.61.22l2.49-1c.52.4 1.08.73 1.69.98l.38 2.65c.05.24.26.42.49.42h4c.24 0 .44-.18.49-.42l.38-2.65c.61-.25 1.17-.59 1.69-.98l2.49 1c.23.09.49 0 .61-.22l2-3.46a.5.5 0 0 0-.12-.64l-2.11-1.65Z"/>
                </svg>
            },
            {
                label: 'Write', action: () => handleOpenTextEditor(),
                className: 'write-journal-bttn'
            },
        ];
    }, [location.pathname, isGuest, notifCount, navigate, navigatePath, handleOpenTextEditor]);

    const handleOnboardingComplete = useCallback((action) => {
        setShowOnboarding(false);
        queryClient.invalidateQueries({ queryKey: ['userData', session?.user?.id] });
        if (action === 'write') {
            handleOpenTextEditor();
        } else if (action === 'story') {
            navigate('/home/stories/new');
        }
        // 'explore' → just close, user lands on feed
    }, [queryClient, session, handleOpenTextEditor, navigate]);

    const handleClickMobileProfileLink = () =>{
        setShowMobileSideBar(true)
    }
    const handleClickCloseSidebar = () =>{
        setShowMobileSideBar(false)
    }

    const handleOpenOpinionTextEditor = () =>{
        setShowOpinionEditor(true)
    }
    const handleCloseOpiniionTextEditor = () =>{
        setShowOpinionEditor(false);
    }

    useEffect(() => {
        const launchState = location.state;
        if(!launchState?.openEditor){
            return;
        }

        handleOpenTextEditor({
            initialTitle: launchState?.initialTitle || ''
        });

        navigate(location.pathname, {replace: true, state: null});
    }, [location.state, location.pathname, navigate, handleOpenTextEditor]);

    //handle show links header when stop scrolling and hides header when scrolling
    // useEffect(() =>{
    //     const handleScroll = (e) => {
    //         clearTimeout(scrollRefTimeOut.current)
    //         setShowHeaders(false)

    //         scrollRefTimeOut.current = setTimeout(() => {
    //             setShowHeaders(true)
    //         }, 500);
    //     }

    //     document.addEventListener('scroll', handleScroll, true);

    //     return() => {
    //         document.removeEventListener('scroll', handleScroll, true);
    //         clearTimeout(scrollRefTimeOut.current)
    //     }
    // }, [])

    useEffect(() => {
        if(session && !loading && user){
            const profileData = user?.userData?.[0];
            const exists = !!profileData;
            const onboarded = profileData?.onboarding_completed ?? true;
            if(!exists || !onboarded){
                setOnboardingUserExists(exists);
                setShowOnboarding(true);
            }
        }
    },[session, loading, user])



    if(isLoading && !isGuest){
        return(
            <Loader/>
        )
    }

    return(
        <>
        {!isGuest && showOnboarding && (
            <OnboardingWizard
                onComplete={handleOnboardingComplete}
                userExists={onboardingUserExists}
            />
        )}

        <AnimatePresence>
        {!isGuest && showEditor && (
            <Editor
                key={'main-editor'}
                onClose={handleCloseEditor}
                initialTitle={editorLaunchConfig.initialTitle}
                promptId={editorLaunchConfig.promptId}
                promptText={editorLaunchConfig.promptText}
                draftId={editorLaunchConfig.draftId}
                draftContent={editorLaunchConfig.draftContent}
            />
        )}

        {!isGuest && showOpinionEditor && (
            <OpinionEditor onClose={handleCloseOpiniionTextEditor}/>
        )}

        </AnimatePresence>

        <div className="home-parent-container">
             <div className="side-bar-holder-container">
                <Sidebar links={links}/> {/*passing the setShowEditor to this component to be used as a state setter inside this component*/}
            </div>
            <div id="main-content" className="center-bar-holder-container">

                {/* <AnimatePresence>
                {showHeaders && (
                    <motion.div 
                    className="newsfeed-header"
                    initial={{opacity: 0}}
                    animate={{opacity: 1, transition: {type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
                    exit={{ opacity: 0, y: -20,
                        transition: { 
                            duration: 0.2,
                            ease: "easeOut"
                        }
                    }}
                    >
                        {header_links.map((header_link, index) => (
                            <div key={index} className="header-links">
                                {header_link.label}
                            </div>
                        ))}
                    </motion.div>
                )}
                </AnimatePresence> */}

                <AnimatePresence mode="wait">
                    <motion.div
                        key={location.pathname}
                        initial={{ opacity: 0, y: 8 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0 }}
                        transition={{ duration: 0.2, ease: [0.25, 1, 0.5, 1] }}
                        style={{ width: '100%' }}
                    >
                        <Outlet context={{ clickOpenSidebar: handleClickMobileProfileLink, handleOpenTextEditor }} />
                    </motion.div>
                </AnimatePresence>
            </div>
            <div className="sidebar-right-holder-container">
                {/* Log out */}
                {!isMobile && !isOpinionsViewer &&(
                    <SidebarOpinions openEditor={handleOpenOpinionTextEditor}/>
                )}

            </div>

            {!isGuest && !isOpinionsPage && !isOpinionsViewer && (
                <WriteJournalButton onOpen={handleOpenTextEditor} hideOnHomeFeed={location.pathname === '/home' || location.pathname === '/home/opinions'}/>
            )}

            <MobileNavlink />
        </div>

        {showMobileSideBar && (
            <MobileSidebarLink onclose={handleClickCloseSidebar}/>
        )}
        </>
    )
}
export default HomePage

