    }

    /* ── Reply Card mobile ── */
    .rc-reply {
        gap: 0.45rem;
    }
    .rc-thread {
        padding-left: calc(var(--depth, 0) * 0.5rem);
    }
    .rc-avatar-col {
        width: 24px;
    }
    .rc-avatar-col .so-avatar-outer {
        width: 24px;
        height: 24px;
    }
    .rc-avatar-col .so-avatar-outer .so-avatar {
        width: 24px;
        height: 24px;
    }
    .rc-avatar {
        width: 18px;
        height: 18px;
    }
    .rc-username {
        font-size: 0.72rem;
        max-width: 100px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
    }
    .rc-body {
        font-size: 0.8rem;
    }
    .rc-show-replies,
    .rc-reply-btn {
        font-size: 0.68rem;
    }
    .rc-load-more {
        font-size: 0.7rem;
        margin-left: calc(24px + 0.65rem);
    }

    /* ── Write Opinion FAB mobile ── */
    .write-opinion-fab {
        right: 1.25rem;
        bottom: 6.5rem;
        width: 54px;
        height: 54px;
    }
}
@media(max-width: 432px){
    .oe-card {
        width: 92%;
    }

    .write-opinion-fab {
        right: 1rem;
        bottom: 6rem;
        width: 50px;
        height: 50px;
    }
}

