  1→import { useQuery, useQueryClient } from "@tanstack/react-query";
  2→import { useLocation } from "react-router-dom";
  3→import { addReplyOpinion, getViewOpinion } from "../../../API/Api";
  4→import { useAuth } from "../../Context/useAuth";
  5→import { useState, useRef } from "react";
  6→import { motion, AnimatePresence } from "framer-motion";
  7→import formatPostDate from "../../../helpers/formatDateString";
  8→import OpinionsReplyCard from "./OpinionsCardRepy";
  9→import VerifiedBadge from "../Badge/VerifiedBadge";
 10→import MentionText from "../mentions/MentionText";
 11→import useTextareaMention from "../mentions/useTextareaMention";
 12→import MentionDropdown from "../mentions/MentionDropdown";
 13→import { getBadgeRingClass } from "../../utils/badgeRingClass";
 14→
 15→const OpinionViewer = () => {
 16→    const queryClient = useQueryClient();
 17→    const location = useLocation();
 18→    const { opinionId, userId } = location.state;
 19→    const { user, session } = useAuth();
 20→    const textAreaRef = useRef(null);
 21→
 22→    const [replyOpinion, setReplyOpinion] = useState('');
 23→    const [isTyping, setIsTyping] = useState(false);
 24→
 25→    const { textareaProps: mentionTextareaProps, dropdownProps: mentionDropdownProps } = useTextareaMention(replyOpinion, setReplyOpinion, textAreaRef, 280, user?.userData?.[0]?.id);
 26→
 27→    const { data, isLoading } = useQuery({
 28→        queryKey: ['getViewOpinion', opinionId, userId],
 29→        queryFn: ({ queryKey }) => getViewOpinion(queryKey[1], queryKey[2]),
 30→        staleTime: 1000 * 60 * 60,
 31→        gcTime: 1000 * 60 * 60,
 32→        enabled: !!opinionId && !!userId,
 33→    });
 34→
 35→    const cancelTyping = () => {
 36→        setIsTyping(false);
 37→        setReplyOpinion('');
 38→        if (textAreaRef.current) {
 39→            textAreaRef.current.blur();
 40→        }
 41→    };
 42→
 43→    const submitReply = async (receiverId, senderId, parentId) => {
 44→        const formData = new FormData();
 45→        formData.append('opinion', replyOpinion);
 46→
 47→        try {
 48→            await addReplyOpinion(formData, receiverId, senderId, parentId, session?.access_token);
 49→            setIsTyping(false);
 50→        } catch (error) {
 51→            console.error(error);
 52→        } finally {
 53→            setReplyOpinion('');
 54→            queryClient.invalidateQueries({ queryKey: ['getViewOpinion', opinionId, userId] });
 55→            queryClient.invalidateQueries({ queryKey: ['getReplyOpinion', opinionId] });
 56→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 57→        }
 58→    };
 59→
 60→    const opinionData = data?.data;
 61→
 62→    return (
 63→        <>
 64→            {opinionData?.map((opinion) => (
 65→                <motion.div
 66→                    className="so-card-wrapper"
 67→                    key={opinion.id}
 68→                    initial={{ opacity: 0, y: 12 }}
 69→                    animate={{ opacity: 1, y: 0 }}
 70→                    transition={{ duration: 0.3, ease: "easeOut" }}
 71→                    style={{ borderBottom: 'none' }}
 72→                >
 73→                    <div className="so-card so-card--parent">
 74→                        <div className="so-card-content">
 75→                            <div className="so-header-row">
 76→                                <div className={`so-avatar-outer ${getBadgeRingClass(opinion.users.badge)}`}>
 77→                                    <img
 78→                                        className="so-avatar"
 79→                                        src={opinion.users.image_url || '../assets/profile.jpg'}
 80→                                        alt={`${opinion?.users?.name || "User"} profile picture`}
 81→                                    />
 82→                                </div>
 83→                                <span className="so-username">{opinion.users.name}</span>
 84→                                <VerifiedBadge badge={opinion.users.badge} size={14}/>
 85→                            </div>
 86→
 87→                            <div className="so-body so-body--parent">
 88→                                <MentionText text={opinion.opinion} />
 89→                            </div>
 90→
 91→                            <div className="ov-stats-row">
 92→                                <span className="ov-reply-count">
 93→                                    {opinion.reply_count} {opinion.reply_count === 1 ? 'reply' : 'replies'}
 94→                                </span>
 95→                                <span className="so-dot">·</span>
 96→                                <span className="ov-full-date">
 97→                                    {new Date(opinion.created_at).toLocaleDateString('en-US', {
 98→                                        month: 'long',
 99→                                        day: '2-digit',
100→                                        year: 'numeric',
101→                                    })}
102→                                </span>
103→                            </div>
104→
105→                            <div className="ov-divider" />
106→
107→                            <div className="ov-composer">
108→                                <img
109→                                    className="ov-reply-avatar"
110→                                    src={user?.userData[0].image_url || '../assets/profile.jpg'}
111→                                    alt={`${user?.userData?.[0]?.name || "User"} profile picture`}
112→                                />
113→                                <div className="ov-composer-input-wrap">
114→                                    <textarea
115→                                        ref={textAreaRef}
116→                                        maxLength={280}
117→                                        value={replyOpinion}
118→                                        onChange={(e) => { setReplyOpinion(e.target.value); mentionTextareaProps.onChange(e); }}
119→                                        onKeyDown={mentionTextareaProps.onKeyDown}
120→                                        onKeyUp={mentionTextareaProps.onKeyUp}
121→                                        onFocus={() => setIsTyping(true)}
122→                                        className="ov-reply-input"
123→                                        placeholder={`Reply to ${opinion.users.name}...`}
124→                                        rows={1}
125→                                    />
126→                                    <MentionDropdown {...mentionDropdownProps} />
127→
128→                                    <AnimatePresence>
129→                                        {isTyping && (
130→                                            <motion.div
131→                                                className="ov-composer-actions"
132→                                                initial={{ height: 0, opacity: 0 }}
133→                                                animate={{ height: "auto", opacity: 1 }}
134→                                                exit={{ height: 0, opacity: 0 }}
135→                                                transition={{ duration: 0.2 }}
136→                                            >
137→                                                <span className="ov-char-count">
138→                                                    {replyOpinion.length > 0 ? `${replyOpinion.length}/280` : ''}
139→                                                </span>
140→                                                <div className="ov-btn-row">
141→                                                    <button
142→                                                        onClick={cancelTyping}
143→                                                        className="ov-btn-cancel"
144→                                                    >
145→                                                        Cancel
146→                                                    </button>
147→                                                    <button
148→                                                        disabled={replyOpinion.trim().length === 0}
149→                                                        onClick={() => submitReply(userId, user?.userData[0].id, opinion.id)}
150→                                                        className={`ov-btn-submit ${replyOpinion.trim().length === 0 ? 'ov-btn-disabled' : ''}`}
151→                                                    >
152→                                                        Reply
153→                                                    </button>
154→                                                </div>
155→                                            </motion.div>
156→                                        )}
157→                                    </AnimatePresence>
158→                                </div>
159→                            </div>
160→
161→                            <div className="ov-divider" />
162→
163→                            <OpinionsReplyCard opinionId={opinion.id} depth={0} />
164→                        </div>
165→                    </div>
166→                </motion.div>
167→            ))}
168→        </>
169→    );
170→};
171→
172→export default OpinionViewer;
